query:
UPDATE site_content SET value = 'Essence of Duality' WHERE key = 'album_title';
UPDATE site_content SET value = 'Where Raga Meets Jazz' WHERE key = 'hero_subtitle';
UPDATE site_content SET value = '"An exploration of the space between Indian classical music and jazz, where raga and improvisation meet in unexpected and beautiful ways."' WHERE key = 'hero_quote';
UPDATE site_content SET value = 'Essence of Duality is the debut crossover jazz album by Cologne-based sitarist Hindol Deb. The album explores and crosses the boundaries of jazz and Indian classical music, making aesthetic connections between the two. It is a sincere attempt to move beyond the exotic yet stereotypical image of the sitar in the West, and of Indo-Jazz fusion in particular. The album is the logical result of Hindol''s move to Germany in 2015, in search of new sounds and compositional styles.' WHERE key = 'album_description';
UPDATE site_content SET value = 'October 1, 2021' WHERE key = 'album_release_date';
UPDATE site_content SET value = 'Crossover Jazz / World Music' WHERE key = 'album_genre';
UPDATE site_content SET value = 'Medieval Raga Records' WHERE key = 'album_label';
UPDATE site_content SET value = '1 hr 10 min · 9 tracks' WHERE key = 'album_duration';
UPDATE site_content SET value = 'It started with the duality of two styles of music. On the one hand, my classical Indian background, which I brought with me to Germany, and on the other, music built on harmonies. I had wanted to bring these two worlds together ever since I listened to the late night shows on the radio in 10th grade.' WHERE key = 'artist_quote';
UPDATE site_content SET value = '— Hindol Deb, Qantara.de, 2021' WHERE key = 'artist_quote_attribution';

